// // This module implements a 2-input NOR gate with an enable signal.
// When en is 1, out will be the OR of in1 and in2.
// When en is 0, out will be 1 regardless of the values of in1 and in2.
module nor_gate_with_enable (
    input in1,
    input in2,
    input en,
    output out
);

reg out_reg;

always @(*) begin
    if (en == 1'b0) begin
        out_reg = 1'b0;
    end else begin
        out_reg = ~(in1 | in2);
    end
end

assign out = out_reg;

endmodule

